import{_ as t,o as a,c as i,a3 as o}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"106. Facilities","description":"","frontmatter":{"title":"106. Facilities","eba":"Allied Health Professionals 2021-2026","topics":["accommodation"]},"headers":[],"relativePath":"ebas/allied-health/ohs/106-facilities.md","filePath":"ebas/allied-health/ohs/106-facilities.md"}'),s={name:"ebas/allied-health/ohs/106-facilities.md"};function r(n,e,l,p,c,h){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="_106-facilities" tabindex="-1">106. Facilities <a class="header-anchor" href="#_106-facilities" aria-label="Permalink to &quot;106. Facilities&quot;">​</a></h1><p><strong>106.1</strong> The Employer acknowledges that:</p><p><strong>(a)</strong> the OHS Act requires Employers to provide a work environment that is safe and without risk to Employees’ health, so far as reasonably practicable, and</p><p><strong>(b)</strong> they are required by the OHS Act law to consult with affected Employees and HSRs, so far as reasonably practicable, when making decisions about the adequacy of facilities for the welfare of employees.</p><p><strong>106.2</strong> The Employer must provide and continue to provide adequate facilities for the welfare of Employees at any workplace under the Employer’s management and control, subject to subclause 106.4 below. Such facilities include a room for the taking of meal breaks and rest breaks, staff only toilets, change rooms / shower, and secure personal storage.</p><p><strong>106.3</strong> The WorkSafe Compliance Code – Workplace Amenities and Work Environment (Compliance Code) is an appropriate guide on how to fulfil these duties to the extent that they relate to providing appropriate facilities for the work environment and appropriate workplace amenities for Employees.</p><p><strong>106.4</strong> Where the Employer cannot:</p><p><strong>(a)</strong> provide the facilities referred to at subclause 106.2 because it is not reasonably practicable to do so; or</p><p><strong>(b)</strong> where the Employer cannot continue to provide the facilities due to refurbishment or other unforeseeable disruption; subclause 106.5 applies.</p><p><strong>106.5</strong> In the circumstances in subclause 106.4, the Employer will:</p><p><strong>(a)</strong> in consultation with Employees and their HSRs, conduct an assessment of workplace facilities to identify any risks to the health, safety and wellbeing of staff. The assessment will consider the requirements outlined in the Compliance Code;</p><p><strong>(b)</strong> develop and implement an action plan to improve staff health, safety and wellbeing. The action plan will require them to take all reasonable steps to mitigate not providing the facilities required by subclause 106.2 and to identify timeframes, including any timeframes to provide the facilities at subclause 106.2. This information will be provided to the affected Employees and the Union in writing; and</p><p><strong>(c)</strong> as soon as is reasonably practicable provide and continue to provide the facilities referred to at subclause 106.2 and prioritise providing these facilities, save that secure personal storage suitable to the circumstances must be available within two (2) years of the Agreement commencing operation or earlier if practicable.</p><p><strong>106.6</strong> A member/s of the WIC and / or the Union may request and the Employer will provide in writing information regarding the facilities required to meet the requirements of the OHS Act and/or this clause 106, including:</p><p><strong>(a)</strong> why it is not reasonably practicable for the Employer to provide the facilities referred to at subclause 106.2;</p><p><strong>(b)</strong> the steps to mitigate any hazard / risk where such facilities cannot be provided; and</p><p><strong>(c)</strong> details of any new sites the Employer is building or any existing sites they are refurbishing, and steps they are taking to provide the facilities referred to at subclause 106.2 as part of this construction.</p><p><strong>106.7</strong> Where refurbishment or construction is proposed, Employers will, where reasonably practicable, provide the facilities for the welfare of Employees as described at subclause 106.2 as part of this refurbishment or construction.</p><p>SIGNATORIES</p><p>Signed on behalf of each Employer listed in <a href="/eba/ebas/allied-health/appendices/1-list-of-employers.html">Appendix 1</a> by:</p><p>Signed on behalf of the Health Services Union Victoria No. 3 Branch (trading as the Victorian Allied Health Professionals Association) as a representative of Employees covered by the Agreement:</p><p>Craig McGregor Witness signature</p><p>Authority to sign: Witness name: Alex Leszczynski Secretary of the Health Services Union Victoria No. 3 Branch (trading as the Victorian Allied Health Professionals Association), employee bargaining representative</p><p>Address: Date: 28/10/2022 Level 1, 62 Lygon Street Carlton, VIC 3053</p>',24)])])}const m=t(s,[["render",r]]);export{f as __pageData,m as default};
